//src.components/MyPet/MyPetForm.jsx

//나의 반려동물 등록 페이지 백엔드 엔드포인트 : /api/pet/enroll

import React, { useState } from "react";
import axios from "axios";
import './MyPetForm.css';

function MyPetForm() {
    const [form, setForm] = useState({
        name: '',
        profile: '',
        adopt: '',
        type: '',
        weight: '',
        size: '',
        age: '',
        gender: '',
    });
    const [errors, setErrors] = useState({});
    const [isLoading, setIsLoading] = useState(false);

    const handleChange = (e) => {
        setForm({
            ...form,
            [e.target.name]: e.target.value
        });
        //에러 메시지 초기화
        if (errors[e.target.name]) {
            setErrors({
                ...errors,
                [e.target.name]: ''
            });
        }
    };

    const validateForm = () => {
        const newErrors = {};

        if (!form.name.trim()) {
            newErrors.name = '반려동물의 이름을 입력해주세요';
        }

        if (!form.type.trim()) {
            newErrors.type = '반려동물 종류를 선택해주세요';
        }

        if (!form.gender.trim()) {
            newErrors.gender = '성별을 선택해주세요';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    }

    const handleSubmit = async (e) => {
        e.preventDefault();
        console.log("🟡 handleSubmit called");
        if (!validateForm()) {
            console.log("🔴 유효성 검사 실패", errors);
            return;
        }

        setIsLoading(true);
        console.log("🟢 유효성 통과, 서버에 전송 시작");

        try {
            //백엔드 반려동물 등록 POST
            const { ...sendForm } = form;
            const response = await axios.post('/api/pet/enroll', sendForm);
            alert('반려동물 등록이 완료되었습니다! 🐕');

            setForm({
                name: '',
                profile: '',
                adopt: '',
                type: '',
                weight: '',
                size: '',
                age: '',
                gender: '',
            });
        } catch (error) {
            console.error(error);
            alert("반려동물 등록 실패: " + (error.response?.data || "오류가 발생했습니다."));
        } finally {
            setIsLoading(false);
        }
    }

    return (
        <div className="mypet-container">
            <div className="mypet-card">
                <div className="form-header">
                    <div className="paw-icon">🐾</div>
                    <h2>반려동물 등록하기</h2>
                    <p>소중한 반려동물의 정보를 등록해주세요</p>
                </div>

                <form onSubmit={handleSubmit} className="mypet-form">
                    <div className="form-group">
                        <label htmlFor="name">반려동물 이름 *</label>
                        <input
                            id="name"
                            name="name"
                            type="text"
                            placeholder="예: 멍멍이"
                            value={form.name}
                            onChange={handleChange}
                            className={errors.name ? 'error' : ''}
                        />
                        {errors.name && <span className="error-message">{errors.name}</span>}
                    </div>

                    <div className="form-group">
                        <label htmlFor="type">반려동물 종류 *</label>
                        <select
                            id="type"
                            name="type"
                            value={form.type}
                            onChange={handleChange}
                            className={errors.type ? 'error' : ''}
                        >
                            <option value="">종류를 선택해주세요</option>
                            <option value="dog">강아지</option>
                            <option value="cat">고양이</option>
                            <option value="bird">새</option>
                            <option value="fish">물고기</option>
                            <option value="other">기타</option>
                        </select>
                        {errors.type && <span className="error-message">{errors.type}</span>}
                    </div>

                    <div className="form-group">
                        <label htmlFor="gender">성별 *</label>
                        <select
                            id="gender"
                            name="gender"
                            value={form.gender}
                            onChange={handleChange}
                            className={errors.gender ? 'error' : ''}
                        >
                            <option value="">성별을 선택해주세요</option>
                            <option value="male">수컷</option>
                            <option value="female">암컷</option>
                        </select>
                        {errors.gender && <span className="error-message">{errors.gender}</span>}
                    </div>

                    <div className="form-group">
                        <label htmlFor="age">나이</label>
                        <input
                            id="age"
                            name="age"
                            type="number"
                            placeholder="예: 3"
                            value={form.age}
                            onChange={handleChange}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="weight">몸무게 (kg)</label>
                        <input
                            id="weight"
                            name="weight"
                            type="number"
                            step="0.1"
                            placeholder="예: 5.2"
                            value={form.weight}
                            onChange={handleChange}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="size">크기</label>
                        <select
                            id="size"
                            name="size"
                            value={form.size}
                            onChange={handleChange}
                        >
                            <option value="">크기를 선택해주세요</option>
                            <option value="small">소형</option>
                            <option value="medium">중형</option>
                            <option value="large">대형</option>
                        </select>
                    </div>

                    <div className="form-group">
                        <label htmlFor="adopt">입양일</label>
                        <input
                            id="adopt"
                            name="adopt"
                            type="date"
                            value={form.adopt}
                            onChange={handleChange}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="profile">특이사항</label>
                        <textarea
                            id="profile"
                            name="profile"
                            placeholder="반려동물에 대한 특이사항이나 소개를 작성해주세요"
                            value={form.profile}
                            onChange={handleChange}
                            rows="4"
                        />
                    </div>

                    <button
                        type="submit"
                        className={`submit-btn ${isLoading ? 'loading' : ''}`}
                        disabled={isLoading}
                    >
                        {isLoading ? (
                            <>
                                <span className="loading-spinner"></span>
                                등록 중...
                            </>
                        ) : (
                            '반려동물 등록 완료 🐕'
                        )}
                    </button>
                </form>
            </div>
        </div>
    );
}

export default MyPetForm;
